const a={name:"Störböna",icon:"storbona",family:"Baljväxter",familyLatin:"Fabaceae",difficulty:"Enkel",difficultyWhy:"Direktsås, fixar sitt eget kväve och ger skörd i veckor. Det enda du behöver ordna är stöd - sen sköter hon resten själv.",zones:{outdoor:[1,2,3,4,5],indoor:null,greenhouse:[6,7]},days:"60-80",spacing:"15-20 cm",rowSpacing:"60-80 cm",depth:"3-5 cm",ph:{min:6,max:7,ideal:6.5},optimalConditions:{sun:{level:"Full sol",icon:"sun",detail:"Minst 6 timmar sol per dag. Störbönan älskar värme och ljus - hon klättrar mot solen och belönar dig med fler baljor ju mer sol hon får."},temperature:{min:10,max:30,ideal:"18-25°C",detail:"Gror inte under 10°C i jorden - ha tålamod och vänta tills marken verkligen värmt upp sig. Hon trivs bäst i 18-25°C och slutar växa vid temperaturer under 12°C. Frost är döden - inte en chans."},wind:{level:"Skyddat",detail:"Störbönan klättrar 2-3 meter högt och behöver vindskydd. Höga plantor på störar eller spaljéer fångar vinden som segel - en ordentlig blåst kan knäcka rankor och välta stöd."}},watering:{need:"Medel",icon:"water",summary:"Störbönan klarar sig hyfsat på egen hand, men under blomning och baljesättning vill hon ha ordentligt med vatten. Torka då = tomma baljor och sega bönor.",phases:[{phase:"Groning (0-2 veckor)",need:"Medel",tip:"Vattna väl vid sådd - fröna behöver fukt för att svälla och gro. Jorden ska vara jämnt fuktig men inte dränkt."},{phase:"Tillväxt (2-5 veckor)",need:"Låg",tip:"Störbönan bygger sin rankbas nu och klarar sig bra på naturlig nederbörd. Lite lagom törst får rötterna att söka sig djupare."},{phase:"Klättring & blomning (5-8 veckor)",need:"Hög",tip:"Kritisk period! Hon växer på höjden och blommar samtidigt - vattenstress nu gör att blommorna faller av utan att sätta baljor. Vattna djupt 2-3 gånger i veckan vid torrt väder."},{phase:"Baljesättning (8+ veckor)",need:"Medel-Hög",tip:"Fortsätt vattna jämnt. Baljorna växer snabbt nu och behöver vatten för att bli spröda och saftiga istället för sega och trådiga."}],mistakes:["Sår för tidigt i kall jord - fröna ruttnar istället för att gro","Glömmer vattna under blomning - den absolut viktigaste perioden för skörd","Vattnar ovanifrån sent på dagen - fuktiga blad bjuder in svampsjukdomar"],tip:"Mulcha runt plantorna med gräsklipp eller halm. Det håller fukten jämn, jorden varm och ogräset borta - tre flugor i en smäll."},soil:"Trivs bäst i lös, varm och mullrik jord med bra dränering. Hon är inte kräsen men ger mer i en omhändertagen odlingsbädd.",soilTips:["Inget extra kväve behövs - störbönan fixar sitt eget via Rhizobium-bakterier på rötterna","Jobba in lite kompost på hösten före - det ger den mullrika, luftiga jord som bönor älskar","Undvik att gödsla med stallgödsel samma år - för mycket kväve ger massor av blad men få baljor"],timeline:{1:[{phase:"Direktså",months:"Maj",icon:"seedling"},{phase:"Klättring & blomning",months:"Jun-Jul",icon:"flower"},{phase:"Skörd",months:"Jul-Sep",icon:"harvest"}],4:[{phase:"Förså inomhus",months:"Maj",icon:"seedling"},{phase:"Direktså / plantera ut",months:"Jun",icon:"seedling"},{phase:"Blomning",months:"Jul",icon:"flower"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}],6:[{phase:"Direktså (växthus)",months:"Jun",icon:"seedling"},{phase:"Blomning",months:"Jul-Aug",icon:"flower"},{phase:"Skörd",months:"Aug-Sep",icon:"harvest"}]},nutritionData:[{month:"Maj",N:5,P:15,K:10,label:"Groning"},{month:"Jun",N:10,P:25,K:15,label:"Tillväxt & klättring"},{month:"Jul",N:10,P:45,K:40,label:"Blomning"},{month:"Aug",N:8,P:50,K:55,label:"Baljesättning"},{month:"Sep",N:5,P:30,K:40,label:"Skörd"}],nutritionTips:[{timing:"Vid sådd",tip:"Inget kväve! Störbönan fixar sitt eget via Rhizobium-bakterier. En liten giva benmjöl eller stenfosfat för fosfor räcker gott."},{timing:"Blomning",tip:"En lätt giva kaliumrik gödsel (vedaska eller alggödsel) stärker blomningen och hjälper baljorna att fylla på."},{timing:"Under säsongen",tip:"Störbönan är anspråkslös - hon ger mer till jorden än hon tar. Övergödsla med kväve och du får en grön vägg utan baljor."},{timing:"Efter skörd",tip:"Klipp av plantan vid markytan men LÅT RÖTTERNA SITTA KVAR. Kvävebakterierna fortsätter gödsla jorden åt nästa gröda - helt gratis."}],companions:{good:[{id:"morot",name:"Morot",icon:"morot",why:"Morötter luckrar jorden på djupet medan störbönan fixar kväve - drömgrannar som hjälper varandra"},{id:"gurka",name:"Gurka",icon:"vegetable",why:"Gurkorna breder ut sig vid marken och håller fukten medan bönorna klättrar uppåt - smart samarbete i höjd och bredd"},{id:"squash",name:"Squash",icon:"vegetable",why:"Klassisk kombination - squash täcker marken med sina stora blad, bönan klättrar uppåt och fixar kväve åt alla"},{name:"Majs",icon:"vegetable",why:"De tre systrarnas metod - majs som levande bönstör, bönan fixar kväve och squash täcker marken. Urgammal och genial samplantering."}],bad:[{id:"lok",name:"Lök",icon:"vegetable",why:"Lökväxter anses kunna hämma bönans kvävefixering via sina svavelhaltiga ämnen - bäst att hålla dem åtskilda"},{id:"vitlok",name:"Vitlök",icon:"vegetable",why:"Samma problem som lök - allicin i vitlök kan påverka Rhizobium-bakterierna negativt"}]},rotation:{avoid:[{id:"artor",name:"Ärtor"},{id:"bondbona",name:"Bondböna"},{id:"brytbona",name:"Brytböna"}],avoidWhy:"Alla baljväxter delar sjukdomar som rotröta och bönflugor. Vänta minst 4 år innan du sår baljväxter på samma plats.",goodBefore:[{id:"potatis",name:"Potatis"},{id:"lok",name:"Lök"},{id:"squash",name:"Squash"}],goodBeforeWhy:"Potatisens luckring och lökens sanering gör jorden redo. Squash bryter också sjukdomscykler bra.",goodAfter:[{id:"gronkal",name:"Grönkål",category:"grönsaker"},{id:"sallat",name:"Sallat"},{id:"squash",name:"Squash"}],goodAfterWhy:"Kvävehungriga grödor som kål, sallat och squash älskar jorden efter störböna - den är fullpumpad med kväve."},varieties:[{name:"Neckarkönigin",zones:[1,2,3,4,5],note:"Rikbärande OP-klassiker med gröna, raka baljor. Pålitlig och lättodlad - det säkra valet. Finns hos Impecta och Runåbergs."},{name:"Blauhilde",zones:[1,2,3,4,5],note:"Fantastiskt vacker OP-sort med djupt blålila baljor. Lika god som snygg - baljorna blir gröna vid tillagning. Finns hos Impecta."},{name:"Goldmarie",zones:[1,2,3,4],note:"Gul vaxböna med mild, smörig smak. Kulturarvsmärkt svensk sort som ger vackra gula baljor - fint som kontrast till gröna sorter. Finns hos Impecta."},{name:"Cobra",zones:[1,2,3,4,5],note:"Tidig och pålitlig OP-sort med gröna, trådlösa baljor. Sätter baljor rikligt och tidigt - bra val för kortare säsonger. Finns hos Impecta och Lindbloms."}],problems:[{name:"Bönflugan",symptom:"Fröna gror dåligt eller inte alls - larverna äter fröna inifrån",fix:"Så i varm jord (minst 12°C) så att fröna gror snabbt förbi det känsliga stadiet. Täck med fiberduk de första veckorna."},{name:"Gråmögel (Botrytis)",symptom:"Gråbrunt ludd på blad, stjälkar och baljor, speciellt i fuktigt väder",fix:"Luftig plantering (inte för tätt), vattna vid roten och aldrig ovanifrån. Ta bort drabbade delar direkt."},{name:"Bladlöss",symptom:"Kolonier av gröna eller svarta löss på skottspetsar och baljor",fix:"Spruta av med stark vattenstråle. Nyckelpigorna och blomflugor är dina bästa allierade - locka dem med blommande kryddväxter intill."},{name:"Bönrost",symptom:"Bruna-orange pustlar på bladens undersida, vanligast sent i säsongen",fix:"Ta bort drabbade blad. Bra luftcirkulation och växtföljd. Störbönans höjd ger bättre luftning än buske-bönor, men håll koll ändå."}],goodToKnow:[{icon:"warning",title:"Stöd är ett MÅSTE",text:"Störbönan klättrar 2-3 meter högt och BEHÖVER något att ta tag i. Sätt upp störar, spaljéer eller nät INNAN du sår. Utan stöd får du en trasslig härva på marken som ruttnar och ger minimal skörd. Klassiska bönstörar i tipiform är både snygga och funktionella.",severity:"warning"},{icon:"harvest",title:"Skörda ofta - det ger MER",text:"Störbönans bästa hemlighet: ju oftare du plockar, desto fler baljor sätter hon. Sluta plocka och hon slutar blomma. Skörda varannan till var tredje dag under högsäsong - du blir förvånad över hur mycket en enda klätterplanta kan ge.",severity:"tip"},{icon:"leaf",title:"Kvävefixerare - gratis gödsel",text:"Precis som alla baljväxter fixar störbönan kväve ur luften via Rhizobium-bakterier på rötterna. Klipp av plantan vid skörd men lämna rötterna kvar i jorden. Nästa gröda får gratis gödsling.",severity:"tip"},{icon:"warning",title:"Frost är döden",text:"Störbönan tål INGEN frost. Inte ens en lätt nattfrost. Vänta med sådden tills frostrisken verkligen är över och jorden håller minst 10°C. Bättre en vecka för sent än en dag för tidigt.",severity:"warning"},{icon:"tip",title:"Vacker som insynsskydd",text:"Störbönor på spaljé bildar en tät, grön vägg på 2-3 meter. Perfekt som sommarens insynsskydd på altanen eller för att dölja komposten. Blauhilde med sina lila baljor är extra dekorativ.",severity:"tip"},{icon:"tip",title:"Längre skörd än brytböna",text:"Medan brytbönan ger allt på några veckor, producerar störbönan baljor under hela sommaren så länge du plockar. En rad störbönor kan ge skörd från juli till första frosten.",severity:"tip"},{icon:"warning",title:"Rör inte blöta plantor",text:"Gå aldrig bland bönplantorna när de är blöta av regn eller dagg. Svampsjukdomar sprider sig via vattendroppar och dina händer blir budbärare. Vänta tills plantorna torkat upp.",severity:"warning"}],sowing:{method:"direct",label:"Direktsådd",description:"Störbönan sås helst direkt på friland vid stöden. Vänta tills jorden verkligen är varm (minst 10°C) - kalla, blöta frön ruttnar fort. I zon 4-5 kan du förså inomhus för att vinna tid.",steps:["Sätt upp stöden FÖRST - störar, spaljé eller nät, minst 2 meter högt","Vänta tills frostrisken är över och jorden håller minst 10°C","Gör hål 3-5 cm djupa vid varje stör, eller spår längs spaljén","Lägg 2-3 frön vid varje stör med 15-20 cm avstånd längs spaljé","Täck med jord och tryck till lätt","Vattna försiktigt men ordentligt","Hjälp de unga rankorna att hitta stödet de första dagarna - sen klarar de sig själva"],tips:["Lägg svart plast på såddbädden en vecka innan för att värma jorden - det ger snabbare groning","I zon 4-5: förså i torvkrukor inomhus 2-3 veckor före utplantering. Var försiktig med rötterna!","Bönstörar i tipiform (3-4 störar som möts i toppen) är stabila och vackra","Räkna med 60-80 cm mellan raderna så du kan komma åt och skörda"],indoorWeeks:null},seedSaving:{difficulty:"Enkel",type:"Självpollinerare",biennial:!1,description:"Störbönan är självpollinerare och en av de enklaste grödorna att spara frö från. Låt ett par plantor stå orörda och låt baljorna torka helt på plantan.",steps:["Välj de friskaste och mest produktiva plantorna - märk dem tidigt och PLOCKA INTE baljor från dessa","Låt baljorna sitta kvar tills de är helt torra, gulbruna och skramlar","Plocka de torra baljorna och lägg dem inomhus på tidningspapper i en vecka","Bryt upp baljorna och plocka ut bönorna","Kontrollera att bönorna är hårda och utan fläckar eller hål","Förvara i papperspåse eller glasburk på sval, torr plats"],isolation:"Övervägande självpollinerare men viss korsbefruktning (3-5%) kan förekomma via insekter. 3-6 m avstånd mellan sorter räcker för rimlig sortrenhet.",storageYears:"3-4 år",tip:"Störbönans stora frön är perfekta att börja fröspara med. Lätta att hantera och de håller bra. Runåbergs och Impecta har fina OP-sorter att utgå ifrån."},storage:{shelfLife:"5-7 dagar (färska) / 1-2 år (torkade)",methods:[{method:"Färska i kylskåp",icon:"snowflake",duration:"5-7 dagar",description:"Lägg otvättade bönor i plastpåse i kylskåpet. Tvätta precis innan du lagar dem. Ät helst inom ett par dagar - sprödheten avtar snabbt.",best:!0},{method:"Frysa (bästa långtidslagring)",icon:"snowflake",duration:"8-12 månader",description:"Bryt bönorna i lagom bitar, blanchera 2-3 minuter, kyl i isvatten, torka och frys in på plåt. Flytta till påse. Behåller färg och smak utmärkt.",best:!1},{method:"Inläggning",icon:"storage",duration:"6-12 månader",description:"Klassiskt svenska inlagda bönor i ättikslag med senapsfrön och dill. Perfekt till husmanskost.",best:!1},{method:"Torka",icon:"sun",duration:"1-2 år",description:"Låt baljorna mogna och torka helt på plantan. De torkade bönorna blötläggs och kokas - nyttig stapelvara till soppor och grytor.",best:!1}],tips:["Unga störbönor ska vara spröda och brytas med ett knäpp - sega baljor har hängt för länge","Blanchera och frys in samma dag du skördar - det ger bäst smak och textur","Störbönans längre skörd gör att du kan frysa in i omgångar istället för allt på en gång","Inlagda bönor i ättikslag är en svensk sommarklassiker - recept finns i varenda syltbok"]},harvestCalc:{minPerSqm:1.5,maxPerSqm:3,unit:"kg"}};export{a as storbona};
